SELECT COUNT(*) 
FROM correspondence 
WHERE is_archived = 1;

SELECT notes
FROM revisions
WHERE revision_id = 0;

SELECT operator_id
FROM editor_assignments
WHERE is_completed = 1;

SELECT COUNT(*) 
     FROM correspondence 
     WHERE status = (SELECT status_id FROM statuses WHERE status_name = 'Completed Accept');

SELECT COUNT(*) 
FROM correspondence_types 
WHERE is_default = 1;
